import { LitElement, css, html, nothing } from 'lit';
import { customElement, property, state } from 'lit/decorators.js';
import { api, CompileResult, PreflightComparison } from '../api/client';

type CompilePhase = 'idle' | 'compiling' | 'success' | 'failed';

@customElement('esp-compile-status')
export class EspCompileStatus extends LitElement {
  @property({ type: String }) mac = '';
  @property({ type: Boolean }) hasConfig = false;
  @state() private phase: CompilePhase = 'idle';
  @state() private result: CompileResult | null = null;
  @state() private error = '';
  @state() private acceptedWarnings = false;

  private async triggerCompile(): Promise<void> {
    if (this.phase === 'compiling') return;
    this.phase = 'compiling';
    this.error = '';
    this.result = null;
    this.acceptedWarnings = false;
    try {
      this.result = await api.compileDevice(this.mac);
      const jobStatus = this.result.job?.status;
      if (jobStatus === 'compiling' || jobStatus === 'compile_queued') {
        this.phase = 'success';
      } else {
        this.phase = 'success';
      }
    } catch (err) {
      this.error = err instanceof Error ? err.message : String(err);
      this.phase = 'failed';
    }
  }

  private async flashNow(): Promise<void> {
    try {
      const { job } = await api.startCompileFlash(this.mac);
      if (job) {
        window.location.hash = `/device/${encodeURIComponent(this.mac)}`;
      }
    } catch (err) {
      this.error = err instanceof Error ? err.message : String(err);
    }
  }

  private downloadFactory(): void {
    const url = api.downloadFactoryBinary(this.mac);
    window.open(url, '_blank');
  }

  render() {
    return html`
      <div class="compile-section">
        ${this.phase === 'idle'
          ? html`
              <button class="btn btn-primary" ?disabled=${!this.hasConfig} @click=${this.triggerCompile}>
                ${this.hasConfig ? 'Compile & Install' : 'No config to compile'}
              </button>
            `
          : this.phase === 'compiling'
            ? html`<button class="btn compiling" disabled>Compiling...</button>`
            : this.phase === 'success'
              ? html`
                  <div class="success-banner">&#10003; Build submitted</div>
                  ${this.result?.preflight?.metadata_unavailable
                    ? html`<p class="meta-unavailable">Metadata not available for ESP8266 Arduino firmware.</p>`
                    : this.result?.preflight
                      ? html`
                          ${this.preflightTable(this.result.preflight)}
                          ${this.result.preflight.has_warnings
                            ? html`
                                <div class="warnings">
                                  ${this.result!.preflight!.warnings.map((w) => html`<p>${w}</p>`)}
                                  <label>
                                    <input type="checkbox" .checked=${this.acceptedWarnings} @change=${(event: Event) => (this.acceptedWarnings = (event.target as HTMLInputElement).checked)} />
                                    Flash anyway
                                  </label>
                                </div>
                              `
                            : nothing}
                        `
                      : nothing}
                  <div class="action-row">
                    <button class="btn flash-btn" ?disabled=${this.result?.preflight?.has_warnings && !this.acceptedWarnings} @click=${this.flashNow}>&#9654; Flash via ESP-NOW</button>
                    <button class="btn download-btn" @click=${this.downloadFactory}>&#8595; Download factory .bin</button>
                  </div>
                  <p class="hint">The build has been queued. You can monitor progress on the config page.</p>
                `
              : this.phase === 'failed'
                ? html`
                    <div class="fail-banner">&#10007; Build failed</div>
                    ${this.error ? html`<p class="error-msg">${this.error}</p>` : nothing}
                    <p class="hint">Fix the YAML above and try again.</p>
                    <a class="view-logs-link" href=${`#/device/${encodeURIComponent(this.mac)}/config`}>View build log →</a>
                  `
                : nothing}
      </div>
    `;
  }

  private preflightTable(preflight: PreflightComparison) {
    const chip = preflight.chip;
    const name = preflight.name;
    const bd = preflight.build_date;

    return html`
      <div class="preflight-section">
        <h4>Preflight</h4>
        <table class="preflight-table">
          <tr>
            <td>Name</td>
            <td>
              ${name.new || '-'}
              <span class="badge ${name.match ? 'match' : 'mismatch'}">${name.match ? 'MATCH' : 'MISMATCH'}</span>
            </td>
          </tr>
          <tr>
            <td>Build</td>
            <td>
              ${bd.status !== 'unknown' && bd.delta ? `${bd.status.toUpperCase()} ${bd.delta}` : bd.status.toUpperCase()}
            </td>
          </tr>
          <tr>
            <td>Chip</td>
            <td>
              ${chip.new || '-'}
              <span class="badge ${chip.match ? 'match' : 'mismatch'}">${chip.match ? 'MATCH' : 'MISMATCH'}</span>
            </td>
          </tr>
        </table>
        ${preflight.has_warnings
          ? html`<div class="warnings">${preflight.warnings.map((w) => html`<p>${w}</p>`)}</div>`
          : nothing}
      </div>
    `;
  }

  static styles = css`
    .compile-section {
      margin-top: 8px;
    }
    .compile-btn {
      border: 1px solid var(--ok);
      background: var(--ok);
      color: white;
      padding: 8px 18px;
      font: inherit;
      font-size: 13px;
      font-weight: 500;
      cursor: pointer;
      border-radius: 8px;
      min-width: 200px;
      transition: all 0.12s;
    }
    .compile-btn:hover {
      background: #16a34a;
    }
    .compile-btn:disabled {
      opacity: 0.5;
      cursor: not-allowed;
    }
    .compile-btn.compiling {
      background: var(--accent);
      border-color: var(--accent);
    }
    .btn-primary {
      background: var(--primary);
      color: #fff;
      border-color: var(--primary);
    }
    .btn-primary:hover {
      background: #0d4d5e;
    }
    .success-banner {
      background: #dcfce7;
      color: #166534;
      border: 1px solid var(--ok);
      border-radius: 8px;
      padding: 8px 12px;
      font-weight: 600;
      font-size: 14px;
    }
    .fail-banner {
      background: #fef2f2;
      color: #991b1b;
      border: 1px solid var(--danger);
      border-radius: 8px;
      padding: 8px 12px;
      font-weight: 600;
      font-size: 14px;
    }
    .summary-row {
      display: flex;
      gap: 12px;
      padding: 8px 0;
      font-size: 13px;
      color: var(--muted);
    }
    .build-meta { font-weight: 500; }
    .build-sizes { font-weight: 500; color: var(--ink); }

    .preflight-section {
      margin: 8px 0;
      border: 1px solid var(--line);
      border-radius: 8px;
      padding: 12px;
    }
    .preflight-section h4 {
      margin: 0 0 6px;
      font-size: 12px;
      text-transform: uppercase;
      color: var(--muted);
      font-weight: 600;
    }
    .preflight-table {
      width: 100%;
      border-collapse: collapse;
      font-size: 13px;
    }
    .preflight-table td {
      padding: 4px 0;
    }
    .preflight-table td:first-child {
      font-weight: 500;
      color: var(--muted);
      width: 80px;
    }
    .badge {
      display: inline-block;
      margin-left: 6px;
      padding: 1px 6px;
      font-size: 10px;
      font-weight: 600;
      border-radius: 4px;
    }
    .badge.match { background: #dcfce7; color: #166534; }
    .badge.mismatch { background: #fef2f2; color: #991b1b; }
    .warnings { margin-top: 6px; border-left: 4px solid var(--accent); background: #fffbeb; padding: 12px; border-radius: 6px; display: grid; gap: 8px; }
    .warnings p {
      margin: 0;
      font-size: 13px;
      color: #7c3f00;
    }
    .warnings label {
      font-weight: 500;
      display: flex;
      gap: 8px;
      align-items: center;
    }

    .action-row {
      display: flex;
      gap: 8px;
      margin: 10px 0;
    }
    .meta-unavailable {
      color: var(--muted);
      font-style: italic;
      margin: 8px 0;
    }
    .btn {
      display: inline-flex;
      align-items: center;
      gap: 6px;
      font-family: inherit;
      font-size: 13px;
      font-weight: 500;
      padding: 8px 16px;
      border-radius: 8px;
      border: 1px solid var(--line);
      background: var(--surface);
      color: var(--ink);
      cursor: pointer;
      transition: all 0.12s;
    }
    .btn:hover {
      background: #f8fafc;
      border-color: #cbd5e1;
    }
    .flash-btn {
      background: var(--primary);
      color: #fff;
      border-color: var(--primary);
    }
    .flash-btn:hover {
      background: #0d4d5e;
    }
    .download-btn {
      background: var(--surface);
    }
    .hint {
      font-size: 11px;
      color: var(--muted);
      font-style: italic;
    }
    .error-msg {
      color: var(--danger);
      font-size: 13px;
      font-weight: 500;
    }
    .view-logs-link {
      display: inline-block;
      margin-top: 8px;
      color: var(--primary);
      font-size: 12px;
      font-weight: 500;
    }
  `;
}

declare global {
  interface HTMLElementTagNameMap {
    'esp-compile-status': EspCompileStatus;
  }
}
